import{_ as a,o as r,c as i,a4 as o}from"./chunks/framework.CoAJCMjA.js";const u=JSON.parse('{"title":"MusicFree","description":"","frontmatter":{},"headers":[],"relativePath":"feature.md","filePath":"feature.md"}'),l={name:"feature.md"};function t(c,e,d,n,s,p){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="musicfree" tabindex="-1">MusicFree <a class="header-anchor" href="#musicfree" aria-label="Permalink to “MusicFree”">​</a></h1><p>曾几何时你为了听音乐无损音乐要搭建各种各样服务，</p><ul><li>「音乐媒体管理」用<a href="https://www.navidrome.org/" target="_blank" rel="noreferrer">Navidrome</a>,</li><li>「音乐标刮削」用<a href="https://xiers-organization.gitbook.io/music-tag-web-v2" target="_blank" rel="noreferrer">MusicTagWeb</a>,</li><li>「音乐搜索和下载」用<a href="https://musicdl.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">MusicDL</a>,</li></ul><p>有没有更好的,有没有一个All in all的方式，让听歌这件事变得简单一点。</p><h2 id="扩展性" tabindex="-1">扩展性 <a class="header-anchor" href="#扩展性" aria-label="Permalink to “扩展性”">​</a></h2><p>我们提供了音乐全生命周期的管理功能</p><p>我们不仅支持基本音乐、专辑、艺术的管理功能，还支持各种各样的扩展功能，例如：</p><ul><li>从音乐的<code>在线搜索</code>到<code>下载</code>，便捷的音乐获取功能</li><li>从音乐的<code>去重</code>到各种格式的<code>播放</code>，全功能的音乐管理，</li><li>从音乐的<code>封面</code>到<code>歌词</code>的刮削，我们提供完整的歌曲信息匹配能力，</li><li>我们支持各种平台的<code>歌单同步</code>功能，</li><li>我们支持艺术家、专辑全功能的信息<code>匹配</code>与<code>刮削</code>，自动帮你补全艺术家的头像、简介</li></ul><p>关键是这里所有的扩展功能我们都是通过<code>插件实现</code>，因此你可以使用各种各样的插件实现自己想要的功能</p><h2 id="兼容性" tabindex="-1">兼容性 <a class="header-anchor" href="#兼容性" aria-label="Permalink to “兼容性”">​</a></h2><p>我们支持完整<code>OpenSubSonic</code> 和部分<code>Navidrome</code>风格的音乐API，因此不管是你在使用的是什么播放器</p><ul><li><a href="https://music.aqzscn.cn/" target="_blank" rel="noreferrer">音流</a>，</li><li><a href="./.html">云净听</a></li><li><a href="https://github.com/dweymouth/supersonic" target="_blank" rel="noreferrer">Supersonic</a></li><li>...</li></ul><p>只要支持OpenSubSonic协议的我们都支持</p>',13)])])}const f=a(l,[["render",t]]);export{u as __pageData,f as default};
